import { ExclusionGroupsDialog } from "../tool-editor/dialogs/exclusion-groups-dialog";
import { ParameterDetailsDialog } from "../tool-editor/dialogs/parameter-details-dialog";
import { ToolDetailsDialog } from "../tool-editor/dialogs/tool-details-dialog";
import { AIChatPanel } from "./ai-chat";
import { CommandTree } from "./command-tree";
import { SavedCommandsDialog } from "./dialogs/saved-commands-dialog";
import { ParameterList } from "./parameter-list";
import { PreviewTabs } from "./preview-tabs";
import { ToolBuilderProvider, useToolBuilder } from "./tool-editor.context";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { SavedCommand, Tool } from "@/registry/commandly/lib/types/commandly";
import { SaveIcon, Edit2Icon, LayersIcon, GitPullRequestIcon, SparklesIcon } from "lucide-react";
import { useState } from "react";
import { toast } from "sonner";

const GITHUB_REPO = "divyeshio/commandly";
const MAX_URL_JSON_LENGTH = 4000;

interface ToolEditorProps {
  tool: Tool;
  onSave?: (tool: Tool) => void;
  isNewTool?: boolean;
  savedCommands?: SavedCommand[];
  onSaveCommand?: (command: string) => void;
  onDeleteSavedCommand?: (commandKey: string) => void;
}

export default function ToolEditor({
  tool: toolToEdit,
  onSave,
  isNewTool = false,
  savedCommands,
  onSaveCommand,
  onDeleteSavedCommand,
}: ToolEditorProps) {
  return (
    <ToolBuilderProvider tool={toolToEdit}>
      <ToolEditorContent
        onSave={onSave}
        isNewTool={isNewTool}
        savedCommands={savedCommands ?? []}
        onSaveCommand={onSaveCommand}
        onDeleteSavedCommand={onDeleteSavedCommand}
      />
    </ToolBuilderProvider>
  );
}

interface ToolEditorContentProps {
  onSave?: (tool: Tool) => void;
  isNewTool?: boolean;
  savedCommands: SavedCommand[];
  onSaveCommand?: (command: string) => void;
  onDeleteSavedCommand?: (commandKey: string) => void;
}

function ToolEditorContent({
  onSave,
  isNewTool = false,
  savedCommands,
  onSaveCommand,
  onDeleteSavedCommand,
}: ToolEditorContentProps) {
  const { tool, setDialogOpen, initializeTool } = useToolBuilder();
  const [chatOpen, setChatOpen] = useState(false);
  const [streamingTool, setStreamingTool] = useState<Tool | null>(null);
  const [isAIGenerating, setIsAIGenerating] = useState(false);

  const [initialToolJson, setInitialToolJson] = useState(() => JSON.stringify(tool));
  const isDirty = JSON.stringify(tool) !== initialToolJson;
  const isValid = tool.name.trim() !== "" && tool.displayName.trim() !== "";

  const handleContribute = async () => {
    const json = JSON.stringify(tool, null, 2);
    const filePath = `public/tools-collection/${tool.name}.json`;

    if (isNewTool) {
      const message = encodeURIComponent(`feat(tools): add ${tool.name}`);
      const filename = encodeURIComponent(filePath);
      if (json.length <= MAX_URL_JSON_LENGTH) {
        window.open(
          `https://github.com/${GITHUB_REPO}/new/main?filename=${filename}&value=${encodeURIComponent(json)}&message=${message}`,
          "_blank",
        );
      } else {
        await navigator.clipboard.writeText(json);
        toast("JSON copied to clipboard", {
          description: "Paste it into the file editor that will open.",
        });
        window.open(
          `https://github.com/${GITHUB_REPO}/new/main?filename=${filename}&message=${message}`,
          "_blank",
        );
      }
    } else {
      await navigator.clipboard.writeText(json);
      toast("JSON copied to clipboard", {
        description: "Paste it into the file editor that will open to create a PR.",
      });
      window.open(`https://github.com/${GITHUB_REPO}/edit/main/${filePath}`, "_blank");
    }
  };

  return (
    <div className="flex h-[calc(100svh-4rem)] bg-background">
      <div className="flex h-full w-72 flex-col overflow-hidden">
        <div className="flex flex-col justify-center gap-2 border-t border-r border-b border-muted p-1">
          <p className="p-2">Commands</p>
        </div>
        <CommandTree />
      </div>

      <div className="flex h-full flex-1 flex-col overflow-hidden">
        <div className="border-t border-b border-muted p-2">
          <div className="flex justify-between">
            <div className="flex items-center justify-between gap-2">
              <span
                className="ml-3 text-lg font-medium"
                style={{
                  viewTransitionName: `tool-card-title-${tool.name}`,
                }}
              >
                {tool.displayName ? `${tool.displayName} (${tool.name})` : `${tool.name}`}
              </span>
              <Button
                variant="ghost"
                size="sm"
                className="h-6 w-6 p-0"
                onClick={() => setDialogOpen("editTool", true)}
              >
                <Edit2Icon className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex items-center gap-2">
              {onSave && (
                <>
                  {isDirty && !isValid && (
                    <span className="text-xs text-destructive">
                      Name and display name are required
                    </span>
                  )}
                  <Button
                    variant="default"
                    size="sm"
                    disabled={!isDirty || !isValid}
                    onClick={() => {
                      onSave(tool);
                      setInitialToolJson(JSON.stringify(tool));
                      toast("Tool saved successfully!");
                    }}
                  >
                    <SaveIcon className="mr-2 h-4 w-4" />
                    Save
                  </Button>
                </>
              )}
              <Button
                variant="outline"
                size="sm"
                onClick={() => setDialogOpen("savedCommands", true)}
              >
                <SaveIcon className="mr-2 h-4 w-4" />
                Saved Commands
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setDialogOpen("exclusionGroups", true)}
              >
                <LayersIcon className="mr-2 h-4 w-4" />
                Exclusion Groups
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={handleContribute}
              >
                <GitPullRequestIcon className="mr-2 h-4 w-4" />
                Contribute
              </Button>
              <Button
                variant={chatOpen ? "default" : "outline"}
                size="sm"
                onClick={() => setChatOpen((o) => !o)}
              >
                <SparklesIcon className="mr-2 h-4 w-4" />
                Generate
              </Button>
            </div>
          </div>
        </div>

        <div className="flex min-h-0 flex-1 overflow-hidden">
          <div className="flex min-h-0 flex-1 gap-4 overflow-hidden p-4">
            <div className="flex min-w-80 flex-2/5 flex-col overflow-hidden">
              <ScrollArea className="h-full">
                <div className="flex flex-col gap-4 pr-3 pb-4">
                  <ParameterList
                    title="Global Parameters"
                    isGlobal={true}
                  />
                  <ParameterList
                    title="Command Parameters"
                    isGlobal={false}
                  />
                </div>
              </ScrollArea>
            </div>
            <div className="h-full max-w-3xl flex-3/5 overflow-hidden">
              <PreviewTabs
                onSaveCommand={onSaveCommand}
                streamingTool={streamingTool}
                isAIGenerating={isAIGenerating}
              />
            </div>
          </div>
          <AIChatPanel
            tool={tool}
            onApply={initializeTool}
            isOpen={chatOpen}
            onStreamingTool={setStreamingTool}
            onGeneratingChange={setIsAIGenerating}
          />
        </div>
      </div>

      <ParameterDetailsDialog />
      <ToolDetailsDialog />
      <SavedCommandsDialog
        savedCommands={savedCommands}
        onDeleteCommand={onDeleteSavedCommand ?? (() => {})}
      />
      <ExclusionGroupsDialog />
    </div>
  );
}

import {
  Tool,
  Command,
  Parameter,
  ExclusionGroup,
  ParameterValue,
} from "@/registry/commandly/lib/types/commandly";
import {
  cleanupTool,
  createNewCommand,
  defaultTool,
  getAllSubcommands,
  slugify,
} from "@/registry/commandly/lib/utils/commandly";
import {
  createContext,
  useContext,
  useReducer,
  useEffect,
  useMemo,
  useRef,
  ReactNode,
} from "react";
import { toast } from "sonner";

export interface ToolBuilderState {
  tool: Tool;
  selectedCommand: Command;
  selectedParameter: Parameter | null;
  editingCommand: Command | null;
  parameterValues: Record<string, ParameterValue>;
  dialogs: {
    parameterDetails: boolean;
    editTool: boolean;
    savedCommands: boolean;
    exclusionGroups: boolean;
  };
}

type DialogKey = "parameterDetails" | "editTool" | "savedCommands" | "exclusionGroups";

type Action =
  | { type: "INITIALIZE_TOOL"; payload: Tool }
  | { type: "UPDATE_TOOL"; payload: Partial<Tool> }
  | { type: "ADD_SUBCOMMAND"; payload: Command }
  | { type: "DELETE_COMMAND"; payload: string }
  | { type: "UPDATE_COMMAND"; payload: { commandKey: string; updates: Partial<Command> } }
  | { type: "REMOVE_PARAMETER"; payload: string }
  | { type: "SET_DIALOG_OPEN"; payload: { dialog: DialogKey; open: boolean } }
  | { type: "SET_SELECTED_COMMAND"; payload: Command }
  | { type: "SET_SELECTED_PARAMETER"; payload: Parameter | null }
  | { type: "SET_EDITING_COMMAND"; payload: Command | null }
  | { type: "UPSERT_PARAMETER"; payload: Parameter }
  | { type: "ADD_EXCLUSION_GROUP"; payload: ExclusionGroup }
  | { type: "UPDATE_EXCLUSION_GROUP"; payload: ExclusionGroup }
  | { type: "REMOVE_EXCLUSION_GROUP"; payload: string }
  | { type: "SET_PARAMETER_VALUE"; payload: { key: string; value: ParameterValue } };

function getDefaultState(tool: Tool): ToolBuilderState {
  return {
    tool,
    selectedCommand: tool.commands[0] ?? ({} as Command),
    selectedParameter: null,
    editingCommand: null,
    parameterValues: {},
    dialogs: {
      parameterDetails: false,
      editTool: false,
      savedCommands: false,
      exclusionGroups: false,
    },
  };
}

function toolBuilderReducer(state: ToolBuilderState, action: Action): ToolBuilderState {
  switch (action.type) {
    case "INITIALIZE_TOOL":
      return getDefaultState(cleanupTool(action.payload));

    case "UPDATE_TOOL":
      return { ...state, tool: cleanupTool({ ...state.tool, ...action.payload }) };

    case "ADD_SUBCOMMAND":
      return {
        ...state,
        tool: { ...state.tool, commands: [...state.tool.commands, action.payload] },
      };

    case "DELETE_COMMAND": {
      const subcommands = getAllSubcommands(action.payload, state.tool.commands);
      const commandsToDelete = [action.payload, ...subcommands.map((c) => c.key)];
      const newCommands = state.tool.commands.filter((cmd) => !commandsToDelete.includes(cmd.key));
      return {
        ...state,
        tool: {
          ...state.tool,
          commands: newCommands,
          parameters: state.tool.parameters.filter(
            (param) => !commandsToDelete.includes(param.commandKey || ""),
          ),
          exclusionGroups: state.tool.exclusionGroups?.filter(
            (group) => !commandsToDelete.includes(group.commandKey || ""),
          ),
        },
        selectedCommand:
          state.selectedCommand?.key === action.payload ? newCommands[0] : state.selectedCommand,
      };
    }

    case "UPDATE_COMMAND":
      return {
        ...state,
        tool: {
          ...state.tool,
          commands: state.tool.commands.map((cmd) => {
            if (cmd.key === action.payload.commandKey) return { ...cmd, ...action.payload.updates };
            if (action.payload.updates.isDefault) return { ...cmd, isDefault: false };
            return cmd;
          }),
        },
      };

    case "REMOVE_PARAMETER": {
      const next = {
        ...state,
        tool: {
          ...state.tool,
          parameters: state.tool.parameters.filter((p) => p.key !== action.payload),
          exclusionGroups: state.tool.exclusionGroups?.map((group) => ({
            ...group,
            parameterKeys: group.parameterKeys.filter((key) => key !== action.payload),
          })),
        },
      };
      if (state.selectedParameter?.key === action.payload) next.selectedParameter = null;
      return next;
    }

    case "SET_DIALOG_OPEN":
      return {
        ...state,
        dialogs: { ...state.dialogs, [action.payload.dialog]: action.payload.open },
      };

    case "SET_SELECTED_COMMAND":
      return { ...state, selectedCommand: action.payload };

    case "SET_SELECTED_PARAMETER":
      return { ...state, selectedParameter: action.payload };

    case "SET_EDITING_COMMAND":
      return { ...state, editingCommand: action.payload };

    case "UPSERT_PARAMETER": {
      const exists = state.tool.parameters.some((p) => p.key === action.payload.key);
      const newParameters = exists
        ? state.tool.parameters.map((param) => {
            if (param.key !== action.payload.key) return param;
            const updatedParam = {
              ...param,
              ...action.payload,
              dependencies: action.payload.dependencies || [],
              validations: action.payload.validations || [],
              enumValues: action.payload.enumValues || [],
            };
            if (action.payload.isGlobal && action.payload.isGlobal !== param.isGlobal) {
              updatedParam.commandKey = undefined;
            }
            if (action.payload.isGlobal === false && param.isGlobal) {
              updatedParam.commandKey = state.selectedCommand?.key;
            }
            return updatedParam;
          })
        : [...state.tool.parameters, action.payload];
      return { ...state, tool: { ...state.tool, parameters: newParameters } };
    }

    case "ADD_EXCLUSION_GROUP":
      return {
        ...state,
        tool: {
          ...state.tool,
          exclusionGroups: [...(state.tool.exclusionGroups ?? []), action.payload],
        },
      };

    case "UPDATE_EXCLUSION_GROUP":
      return {
        ...state,
        tool: {
          ...state.tool,
          exclusionGroups: state.tool.exclusionGroups?.map((group) =>
            group.key === action.payload.key ? action.payload : group,
          ),
        },
      };

    case "REMOVE_EXCLUSION_GROUP":
      return {
        ...state,
        tool: {
          ...state.tool,
          exclusionGroups: state.tool.exclusionGroups?.filter(
            (group) => group.key !== action.payload,
          ),
        },
      };

    case "SET_PARAMETER_VALUE":
      return {
        ...state,
        parameterValues: { ...state.parameterValues, [action.payload.key]: action.payload.value },
      };

    default:
      return state;
  }
}

interface ToolBuilderContextValue extends ToolBuilderState {
  initializeTool: (tool: Tool) => void;
  updateTool: (updates: Partial<Tool>) => void;
  addSubcommand: (parentKey?: string) => string;
  deleteCommand: (commandKey: string) => void;
  updateCommand: (commandKey: string, updates: Partial<Command>) => void;
  removeParameter: (parameterKey: string) => void;
  addExclusionGroup: (group: Omit<ExclusionGroup, "key">) => void;
  updateExclusionGroup: (updatedGroup: ExclusionGroup) => void;
  removeExclusionGroup: (groupKey: string) => void;
  setDialogOpen: (dialog: DialogKey, open: boolean) => void;
  setSelectedCommand: (command: Command) => void;
  setSelectedParameter: (parameter: Parameter | null) => void;
  setEditingCommand: (command: Command | null) => void;
  upsertParameter: (parameter: Parameter) => void;
  setParameterValue: (key: string, value: ParameterValue) => void;
  getParametersForCommand: (commandKey: string) => Parameter[];
  getGlobalParameters: () => Parameter[];
  getExclusionGroupsForCommand: (commandKey: string) => ExclusionGroup[];
}

const ToolBuilderContext = createContext<ToolBuilderContextValue | null>(null);

interface ToolBuilderProviderProps {
  tool: Tool;
  children: ReactNode;
  initialState?: Partial<ToolBuilderState>;
}

export function ToolBuilderProvider({ tool, children, initialState }: ToolBuilderProviderProps) {
  const [state, dispatch] = useReducer(toolBuilderReducer, undefined, () => ({
    ...getDefaultState(tool),
    ...initialState,
  }));

  const isFirstRender = useRef(true);
  useEffect(() => {
    if (isFirstRender.current) {
      isFirstRender.current = false;
      return;
    }
    dispatch({ type: "INITIALIZE_TOOL", payload: tool });
  }, [tool]);

  const contextValue = useMemo(
    (): ToolBuilderContextValue => ({
      ...state,

      initializeTool: (t: Tool) => dispatch({ type: "INITIALIZE_TOOL", payload: t }),

      updateTool: (updates: Partial<Tool>) => dispatch({ type: "UPDATE_TOOL", payload: updates }),

      addSubcommand: (parentKey?: string) => {
        const newCommand = createNewCommand(parentKey);
        dispatch({ type: "ADD_SUBCOMMAND", payload: newCommand });
        toast("Command Added", { description: "New command has been created successfully." });
        return newCommand.key;
      },

      deleteCommand: (commandKey: string) => {
        dispatch({ type: "DELETE_COMMAND", payload: commandKey });
        toast("Command Deleted", {
          description: "Command and all its subcommands have been deleted.",
        });
      },

      updateCommand: (commandKey: string, updates: Partial<Command>) =>
        dispatch({ type: "UPDATE_COMMAND", payload: { commandKey, updates } }),

      removeParameter: (parameterKey: string) => {
        dispatch({ type: "REMOVE_PARAMETER", payload: parameterKey });
        toast("Parameter Deleted", { description: "Parameter has been removed successfully." });
      },

      addExclusionGroup: (group: Omit<ExclusionGroup, "key">) => {
        const newGroup: ExclusionGroup = {
          ...group,
          key: slugify(group.name),
          commandKey: state.selectedCommand?.key,
        };
        dispatch({ type: "ADD_EXCLUSION_GROUP", payload: newGroup });
        toast("Group Added", {
          description: "New exclusion group has been created successfully.",
        });
      },

      updateExclusionGroup: (updatedGroup: ExclusionGroup) => {
        dispatch({ type: "UPDATE_EXCLUSION_GROUP", payload: updatedGroup });
        toast("Group Updated", { description: "Exclusion group has been updated successfully." });
      },

      removeExclusionGroup: (groupKey: string) => {
        dispatch({ type: "REMOVE_EXCLUSION_GROUP", payload: groupKey });
        toast("Group Removed", { description: "Exclusion group has been removed successfully." });
      },

      setDialogOpen: (dialog: DialogKey, open: boolean) =>
        dispatch({ type: "SET_DIALOG_OPEN", payload: { dialog, open } }),

      setSelectedCommand: (command: Command) =>
        dispatch({ type: "SET_SELECTED_COMMAND", payload: command }),

      setSelectedParameter: (parameter: Parameter | null) =>
        dispatch({ type: "SET_SELECTED_PARAMETER", payload: parameter }),

      setEditingCommand: (command: Command | null) =>
        dispatch({ type: "SET_EDITING_COMMAND", payload: command }),

      upsertParameter: (parameter: Parameter) => {
        const exists = state.tool.parameters.some((p) => p.key === parameter.key);
        dispatch({ type: "UPSERT_PARAMETER", payload: parameter });
        if (exists) {
          toast("Parameter Updated", { description: "Parameter has been updated successfully." });
        } else {
          toast("Parameter Added", {
            description: `New ${parameter.isGlobal ? "global " : ""}parameter has been created successfully.`,
          });
        }
      },

      setParameterValue: (key: string, value: ParameterValue) =>
        dispatch({ type: "SET_PARAMETER_VALUE", payload: { key, value } }),

      getParametersForCommand: (commandKey: string) =>
        state.tool.parameters.filter((p) => !p.isGlobal && p.commandKey === commandKey),

      getGlobalParameters: () => state.tool.parameters.filter((p) => p.isGlobal),

      getExclusionGroupsForCommand: (commandKey: string) =>
        state.tool.exclusionGroups?.filter((group) => group.commandKey === commandKey) ?? [],
    }),
    [state],
  );

  return <ToolBuilderContext.Provider value={contextValue}>{children}</ToolBuilderContext.Provider>;
}

export function useToolBuilder(): ToolBuilderContextValue {
  const context = useContext(ToolBuilderContext);
  if (!context) {
    throw new Error("useToolBuilder must be used within a ToolBuilderProvider");
  }
  return context;
}

export { defaultTool };

import { CommandDialog } from "../tool-editor/dialogs/command-dialog";
import { useToolBuilder } from "./tool-editor.context";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Command } from "@/registry/commandly/lib/types/commandly";
import { ChevronDownIcon, ChevronRightIcon, Edit2Icon, PlusIcon, Trash2Icon } from "lucide-react";
import { useState, useEffect } from "react";

interface CommandNodeProps {
  command: Command;
  level?: number;
  allCommands: Command[];
  toolName: string;
  selectedCommandKey?: string;
  expandedCommands: Set<string>;
  onToggle: (commandKey: string) => void;
  onSelect: (command: Command) => void;
  onEdit: (command: Command) => void;
  onAddSubcommand: (parentKey?: string) => void;
  onDelete: (commandKey: string) => void;
}

function CommandNode({
  command,
  level = 0,
  allCommands,
  toolName,
  selectedCommandKey,
  expandedCommands,
  onToggle,
  onSelect,
  onEdit,
  onAddSubcommand,
  onDelete,
}: CommandNodeProps) {
  const isExpanded = expandedCommands.has(command.key);
  const subcommands = allCommands.filter((cmd) => cmd.parentCommandKey === command.key);
  const hasSubcommands = subcommands.length > 0;
  const isSelected = selectedCommandKey === command.key;
  const isRoot = command.name === toolName;

  return (
    <div key={command.key}>
      <div
        className={`group flex cursor-pointer items-center gap-2 rounded-md p-2 hover:bg-muted/50 ${
          isSelected ? "bg-muted" : ""
        }`}
        style={{ paddingLeft: `${level * 16 + 8}px` }}
        onClick={() => onSelect(command)}
      >
        {hasSubcommands ? (
          <Button
            id="expand-button"
            variant="ghost"
            size="sm"
            className="h-4 w-4 p-0"
            onClick={(e) => {
              e.stopPropagation();
              onToggle(command.key);
            }}
          >
            {isExpanded ? (
              <ChevronDownIcon className="h-3 w-3" />
            ) : (
              <ChevronRightIcon className="h-3 w-3" />
            )}
          </Button>
        ) : (
          <div className="w-4" />
        )}

        <span className="flex-1 text-sm font-medium">{command.name}</span>
        {command.isDefault && (
          <Badge
            variant="secondary"
            className="text-xs"
          >
            default
          </Badge>
        )}
        <Button
          variant="ghost"
          size="sm"
          className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
          onClick={(e) => {
            e.stopPropagation();
            onEdit(command);
          }}
        >
          <Edit2Icon className="h-3 w-3" />
        </Button>
        <Button
          variant="ghost"
          size="sm"
          className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
          onClick={(e) => {
            e.stopPropagation();
            onAddSubcommand(command.key);
          }}
        >
          <PlusIcon className="h-3 w-3" />
        </Button>
        {!isRoot && (
          <Button
            variant="ghost"
            size="sm"
            className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
            onClick={(e) => {
              e.stopPropagation();
              onDelete(command.key);
            }}
          >
            <Trash2Icon className="h-3 w-3 text-destructive" />
          </Button>
        )}
      </div>

      {isExpanded && hasSubcommands && (
        <div>
          {subcommands.map((subcmd) => (
            <CommandNode
              key={subcmd.key}
              command={subcmd}
              level={level + 1}
              allCommands={allCommands}
              toolName={toolName}
              selectedCommandKey={selectedCommandKey}
              expandedCommands={expandedCommands}
              onToggle={onToggle}
              onSelect={onSelect}
              onEdit={onEdit}
              onAddSubcommand={onAddSubcommand}
              onDelete={onDelete}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export function CommandTree() {
  const {
    tool,
    selectedCommand,
    editingCommand,
    addSubcommand,
    setSelectedCommand,
    setEditingCommand,
    deleteCommand,
  } = useToolBuilder();

  const [expandedCommands, setExpandedCommands] = useState<Set<string>>(
    new Set([tool.commands[0]?.key]),
  );
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [lastAddedCommand, setLastAddedCommand] = useState<{
    key: string;
    parentKey?: string;
  } | null>(null);

  const toggleExpanded = (commandKey: string) => {
    setExpandedCommands((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(commandKey)) {
        newSet.delete(commandKey);
      } else {
        newSet.add(commandKey);
      }
      return newSet;
    });
  };

  const handleAddSubcommand = (parentKey?: string) => {
    const newKey = addSubcommand(parentKey);
    setLastAddedCommand({ key: newKey, parentKey });
  };

  useEffect(() => {
    if (!lastAddedCommand) return;
    const { key, parentKey } = lastAddedCommand;
    const newCmd = tool.commands.find((cmd) => cmd.key === key);
    if (newCmd) {
      setSelectedCommand(newCmd);
      if (parentKey) {
        setExpandedCommands((prev) => {
          const newSet = new Set(prev);
          newSet.add(parentKey);
          return newSet;
        });
      }
      setLastAddedCommand(null);
    }
  }, [tool.commands, lastAddedCommand, setSelectedCommand]);

  const handleEdit = (command: Command) => {
    setEditingCommand(command);
    setIsDialogOpen(true);
  };

  const rootCommands = tool.commands.filter((cmd) => !cmd.parentCommandKey);

  return (
    <>
      <ScrollArea className="flex-1 border-r border-muted p-1">
        <div className="p-2">
          {rootCommands.map((command) => (
            <CommandNode
              key={command.key}
              command={command}
              allCommands={tool.commands}
              toolName={tool.name}
              selectedCommandKey={selectedCommand?.key}
              expandedCommands={expandedCommands}
              onToggle={toggleExpanded}
              onSelect={setSelectedCommand}
              onEdit={handleEdit}
              onAddSubcommand={handleAddSubcommand}
              onDelete={deleteCommand}
            />
          ))}
        </div>
        <div className="p-2">
          <Button
            className="w-full"
            onClick={() => handleAddSubcommand()}
          >
            <PlusIcon className="mr-1 h-3 w-3" />
            Add Command
          </Button>
        </div>
      </ScrollArea>
      {editingCommand && (
        <CommandDialog
          isOpen={isDialogOpen}
          onOpenChange={(open) => {
            setIsDialogOpen(open);
            setEditingCommand(null);
          }}
        />
      )}
    </>
  );
}

import { useToolBuilder } from "./tool-editor.context";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ExclusionGroup, ParameterType } from "@/registry/commandly/lib/types/commandly";
import { createNewParameter, validateDefaultValue } from "@/registry/commandly/lib/utils/commandly";
import {
  CheckCircleIcon,
  FileTextIcon,
  FlagIcon,
  GlobeIcon,
  HashIcon,
  LayersIcon,
  PlusIcon,
  Trash2Icon,
  XCircleIcon,
} from "lucide-react";

interface ParameterListProps {
  title: string;
  isGlobal?: boolean;
}

function ParameterIcon({ type }: { type: ParameterType }) {
  switch (type) {
    case "Flag":
      return <FlagIcon className="h-4 w-4" />;
    case "Option":
      return <HashIcon className="h-4 w-4" />;
    case "Argument":
      return <FileTextIcon className="h-4 w-4" />;
    default:
      return <HashIcon className="h-4 w-4" />;
  }
}

export function ParameterList({ title, isGlobal = false }: ParameterListProps) {
  const {
    selectedCommand,
    getGlobalParameters,
    getParametersForCommand,
    getExclusionGroupsForCommand,
    setSelectedParameter,
    removeParameter,
  } = useToolBuilder();

  const globalParameters = getGlobalParameters();
  const commandParameters = selectedCommand?.key
    ? getParametersForCommand(selectedCommand.key)
    : [];
  const exclusionGroups = selectedCommand?.key
    ? getExclusionGroupsForCommand(selectedCommand.key)
    : [];

  const parameters = isGlobal ? globalParameters : commandParameters;

  const getParameterExclusionGroups = (parameterKey: string): ExclusionGroup[] => {
    return exclusionGroups.filter((group) => group.parameterKeys.includes(parameterKey));
  };

  return (
    <div>
      <div className="mb-4 flex items-center justify-between">
        <h3 className="flex items-center gap-2 text-lg font-semibold">
          {isGlobal && <GlobeIcon className="h-5 w-5" />}
          {title} ({parameters.length})
        </h3>
        <Button
          onClick={() => setSelectedParameter(createNewParameter(isGlobal, selectedCommand?.key))}
          size="sm"
        >
          <PlusIcon className="h-4 w-4" />
        </Button>
      </div>

      <div className="space-y-2">
        {parameters.map((parameter) => {
          const validation = validateDefaultValue(parameter);
          const paramGroups = getParameterExclusionGroups(parameter.key);

          return (
            <div
              key={parameter.key}
              className={"cursor-pointer rounded border border-muted p-3 hover:bg-muted/50"}
              onClick={() => setSelectedParameter(parameter)}
            >
              <div className="mb-2 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <ParameterIcon type={parameter.parameterType} />
                  <span className="text-sm font-medium">
                    {parameter.name}
                    {(parameter.longFlag || parameter.shortFlag) && (
                      <span className="ml-1 text-muted-foreground">
                        ({[parameter.longFlag, parameter.shortFlag].filter(Boolean).join(", ")})
                      </span>
                    )}
                  </span>
                </div>
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-6 w-6 p-0"
                  onClick={(e) => {
                    e.stopPropagation();
                    removeParameter(parameter.key);
                  }}
                >
                  <Trash2Icon className="h-3 w-3 text-destructive" />
                </Button>
              </div>
              <div className="flex flex-wrap items-center gap-1">
                {parameter.isRequired && (
                  <Badge
                    variant="destructive"
                    className="text-xs"
                  >
                    required
                  </Badge>
                )}
                <Badge
                  variant="outline"
                  className="text-xs"
                >
                  {parameter.parameterType}
                </Badge>
                <Badge
                  variant="secondary"
                  className="text-xs"
                >
                  {parameter.dataType}
                </Badge>
                {isGlobal && (
                  <Badge
                    variant="default"
                    className="text-xs"
                  >
                    global
                  </Badge>
                )}
                {paramGroups.map((group) => (
                  <Badge
                    key={group.key}
                    variant="secondary"
                    className="flex items-center gap-1 bg-muted text-xs"
                  >
                    <LayersIcon className="h-3 w-3" />
                    {group.name}
                  </Badge>
                ))}
                {!validation.isValid && <XCircleIcon className="h-3 w-3 text-destructive" />}
                {validation.isValid && parameter.defaultValue && (
                  <CheckCircleIcon className="h-3 w-3 text-green-500" />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

