import { useToolBuilder } from "./tool-editor.context";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { Command } from "@/registry/commandly/lib/types/commandly";

export function HelpMenu() {
  const { tool } = useToolBuilder();

  const generateToolPreview = (): string => {
    const rootCommands = tool.commands.filter((cmd) => !cmd.parentCommandKey);
    const globalParams = tool.parameters.filter((p) => p.isGlobal);

    let preview = `${tool.displayName}${tool.version ? ` v${tool.version}` : ""}\n`;
    preview += `${tool.description}\n\n`;

    preview += `USAGE:\n`;
    preview += `  ${tool.name} [GLOBAL OPTIONS] <COMMAND> [OPTIONS] [ARGUMENTS]\n\n`;

    if (globalParams.length > 0) {
      preview += "GLOBAL OPTIONS:\n";

      const globalFlags = globalParams.filter((p) => p.parameterType === "Flag");
      const globalOptions = globalParams.filter((p) => p.parameterType === "Option");

      globalFlags.forEach((flag) => {
        const shortFlag = flag.shortFlag ? `${flag.shortFlag}` : "";
        const longFlag = flag.longFlag ? `${flag.longFlag}` : "";
        const flagStr = shortFlag && longFlag ? `${shortFlag}, ${longFlag}` : shortFlag || longFlag;
        const required = flag.isRequired ? "Required: " : "";
        preview += `  ${flagStr.padEnd(20)} ${required}${flag.description}\n`;
      });

      globalOptions.forEach((option) => {
        const shortFlag = option.shortFlag ? `${option.shortFlag}` : "";
        const longFlag = option.longFlag ? `${option.longFlag}` : "";
        const flagStr = shortFlag && longFlag ? `${shortFlag}, ${longFlag}` : shortFlag || longFlag;
        const valueType = option.dataType.includes("array")
          ? `<value1${option.arraySeparator}value2>`
          : `<${option.dataType}>`;
        const required = option.isRequired ? "Required: " : "";
        preview += `  ${flagStr.padEnd(20)} ${required}${option.description}\n`;
        preview += `  ${" ".repeat(20)} Value: ${valueType}\n`;
      });

      preview += "\n";
    }

    preview += "COMMANDS:\n";
    const printCommand = (command: Command, level = 0) => {
      const indent = "  ".repeat(level + 1);
      preview += `${indent}${command.name.padEnd(20 - level * 2)} ${command.description}\n`;

      const commandParams = tool.parameters.filter(
        (p) => !p.isGlobal && p.commandKey === command.key,
      );

      const flags = commandParams.filter((p) => p.parameterType === "Flag");
      const options = commandParams.filter((p) => p.parameterType === "Option");
      const arguments_ = commandParams.filter((p) => p.parameterType === "Argument");

      if (flags.length > 0) {
        preview += `${indent}  Flags:\n`;
        flags.forEach((flag) => {
          const shortFlag = flag.shortFlag ? `${flag.shortFlag}` : "";
          const longFlag = flag.longFlag ? `${flag.longFlag}` : "";
          const flagStr =
            shortFlag && longFlag ? `${shortFlag}, ${longFlag}` : shortFlag || longFlag;
          const required = flag.isRequired ? "Required: " : "";
          preview += `${indent}    ${flagStr.padEnd(18)} ${required}${flag.description}\n`;
        });
      }

      if (options.length > 0) {
        preview += `${indent}  Options:\n`;
        options.forEach((option) => {
          const shortFlag = option.shortFlag ? `${option.shortFlag}` : "";
          const longFlag = option.longFlag ? `${option.longFlag}` : "";
          const flagStr =
            shortFlag && longFlag ? `${shortFlag}, ${longFlag}` : shortFlag || longFlag;
          const valueType = option.dataType.includes("array")
            ? `<value1${option.arraySeparator}value2>`
            : `<${option.dataType}>`;
          const required = option.isRequired ? "Required: " : "";
          preview += `${indent}    ${flagStr.padEnd(18)} ${required}${option.description}\n`;
          preview += `${indent}    ${" ".repeat(18)} Value: ${valueType}\n`;
        });
      }

      if (arguments_.length > 0) {
        preview += `${indent}  Arguments:\n`;
        arguments_.forEach((arg) => {
          const required = arg.isRequired ? "Required: " : "";
          preview += `${indent}    ${arg.name.padEnd(18)} ${required}${arg.description}\n`;
          if (arg.dataType === "Enum") {
            preview += `${indent}    ${" ".repeat(18)} Values: ${arg.enumValues?.map((e) => e.value).join(", ")}\n`;
          }
        });
      }

      const subcommands = tool.commands.filter((cmd) => cmd.parentCommandKey === command.key);
      if (subcommands.length > 0) {
        preview += `${indent}  Subcommands:\n`;
        subcommands.forEach((subcmd) => {
          printCommand(subcmd, level + 2);
        });
      }
    };

    rootCommands.forEach((cmd) => printCommand(cmd));

    return preview;
  };

  return (
    <ScrollArea className="max-h-[75dvh] w-full rounded-xl p-4">
      <pre className="max-h-[70dvh] w-full rounded-xl p-3 font-mono text-sm">
        {generateToolPreview()}
      </pre>
      <ScrollBar orientation="vertical" />
      <ScrollBar orientation="horizontal" />
    </ScrollArea>
  );
}

import { useToolBuilder } from "../tool-editor.context";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import {
  Parameter,
  ParameterDataType,
  ParameterDependency,
  ParameterDependencyType,
  ParameterEnumValue,
  ParameterType,
  ParameterValidation,
  ParameterValidationType,
} from "@/registry/commandly/lib/types/commandly";
import { slugify, validateDefaultValue } from "@/registry/commandly/lib/utils/commandly";
import { TagsInput } from "@/registry/commandly/ui/tags-input";
import {
  FlagIcon,
  FileTextIcon,
  HashIcon,
  LinkIcon,
  PlusIcon,
  ShieldIcon,
  Trash2Icon,
} from "lucide-react";
import { useEffect, useState } from "react";

export function ParameterDetailsDialog() {
  const { selectedParameter, selectedCommand, tool, setSelectedParameter, upsertParameter } =
    useToolBuilder();

  const commandKey = selectedCommand?.key;

  const availableParameters = selectedParameter
    ? tool.parameters.filter((p) => {
        if (p.key === selectedParameter.key) return false;
        if (selectedParameter.isGlobal) return p.isGlobal;
        return p.isGlobal || p.commandKey === commandKey;
      })
    : [];

  const [parameter, setParameter] = useState<Parameter>(selectedParameter!);
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    setParameter(selectedParameter!);
    setHasChanges(false);
  }, [selectedParameter]);

  const getParameterIcon = (parameterType: string) => {
    switch (parameterType) {
      case "Flag":
        return <FlagIcon className="h-5 w-5" />;
      case "Option":
        return <HashIcon className="h-5 w-5" />;
      case "Argument":
        return <FileTextIcon className="h-5 w-5" />;
      default:
        return <HashIcon className="h-5 w-5" />;
    }
  };

  const isOpen = !!selectedParameter;

  const handleClose = () => {
    setSelectedParameter(null);
    setHasChanges(false);
  };

  const handleSave = () => {
    if (parameter) {
      upsertParameter(parameter);
      setHasChanges(false);
      handleClose();
    }
  };

  const updateParameter = (updates: Partial<Parameter>) => {
    setParameter((prev) => {
      const next = { ...prev, ...updates };
      if (updates.name || updates.longFlag) {
        let generatedKey = slugify(next.longFlag || next.name);

        const existingParam = tool.parameters.find(
          (p) => p.key === generatedKey && p.key !== selectedParameter?.key,
        );
        // If duplicate exists and parameter is not global, prefix with command key
        if (existingParam && !next.isGlobal && commandKey) {
          generatedKey = `${commandKey}-${generatedKey}`;
        }

        next.key = generatedKey;
      }
      return next;
    });
    setHasChanges(true);
  };

  const addDependency = () => {
    if (!parameter || availableParameters.length === 0) return;

    const dependsOnParameterKey = availableParameters[0].key;
    const newDependency: ParameterDependency = {
      key: slugify(`${parameter.key}-${dependsOnParameterKey}`),
      parameterKey: parameter.key,
      dependsOnParameterKey,
      dependencyType: "requires",
    };

    updateParameter({
      dependencies: [...(parameter.dependencies || []), newDependency],
    });
  };

  const updateDependency = (dependencyKey: string, updates: Partial<ParameterDependency>) => {
    if (!parameter) return;
    const updatedDependencies = parameter.dependencies?.map((dep) =>
      dep.key === dependencyKey ? { ...dep, ...updates } : dep,
    );
    updateParameter({ dependencies: updatedDependencies });
  };

  const removeDependency = (dependencyKey: string) => {
    if (!parameter) return;
    const updatedDependencies = parameter.dependencies?.filter((dep) => dep.key !== dependencyKey);
    updateParameter({ dependencies: updatedDependencies });
  };

  const addValidation = () => {
    if (!parameter) return;
    const validationType = "min_length";
    const validationValue = "1";
    const newValidation: ParameterValidation = {
      key: slugify(`${parameter.key}-${validationType}-${validationValue}`),
      parameterKey: parameter.key,
      validationType,
      validationValue,
      errorMessage: "Value is too short",
    };

    updateParameter({
      validations: [...(parameter.validations || []), newValidation],
    });
  };

  const addEnumValue = () => {
    if (!parameter) return;
    const value = "new-value";
    const newEnumValue: ParameterEnumValue = {
      value,
      displayName: "New Value",
      isDefault: false,
      sortOrder: 0,
    };

    updateParameter({
      enumValues: [...(parameter.enumValues ?? []), newEnumValue],
    });
  };

  if (!parameter) return null;

  const validation = validateDefaultValue(parameter);

  const canSaveChanges = () => {
    if (!hasChanges) return false;
    if (parameter.defaultValue && !validation.isValid) {
      return false;
    }

    if (!parameter.name.trim() || !parameter.longFlag?.trim()) {
      return false;
    }
    if (
      availableParameters.some(
        (p) =>
          p.name.trim() === parameter.name.trim() ||
          parameter.longFlag == p.longFlag ||
          (parameter.shortFlag && parameter.shortFlag == p.shortFlag),
      )
    ) {
      return false;
    }

    return true;
  };

  return (
    <Dialog
      open={isOpen}
      onOpenChange={handleClose}
    >
      <DialogContent className="max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {getParameterIcon(parameter.parameterType)}
            {parameter.name}
            {parameter.isGlobal && (
              <Badge
                variant="default"
                className="text-xs"
              >
                global
              </Badge>
            )}
          </DialogTitle>
          <DialogDescription></DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          {/* Basic Info */}
          <div className="grid grid-cols-2 gap-4">
            <div className="flex flex-col gap-2">
              <Label>
                Parameter Name<span className="ml-1 text-destructive">*</span>
              </Label>
              <Input
                value={parameter.name}
                onChange={(e) => updateParameter({ name: e.target.value })}
              />
            </div>
          </div>

          <div className="grid grid-cols-3 gap-4">
            <div className="flex flex-col gap-2">
              <Label>Parameter Type</Label>
              <Select
                value={parameter.parameterType}
                onValueChange={(value: ParameterType) => updateParameter({ parameterType: value })}
              >
                <SelectTrigger className="w-full">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Flag">Flag</SelectItem>
                  <SelectItem value="Option">Option</SelectItem>
                  <SelectItem value="Argument">Argument</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex flex-col gap-2">
              <Label>Data Type</Label>
              <Select
                value={parameter.dataType}
                onValueChange={(value: ParameterDataType) => updateParameter({ dataType: value })}
              >
                <SelectTrigger className="w-full">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="String">String</SelectItem>
                  <SelectItem value="Number">Number</SelectItem>
                  <SelectItem value="Boolean">Boolean</SelectItem>
                  <SelectItem value="Enum">Enum</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center space-x-2 pt-6">
              <Switch
                id="isGlobal"
                checked={parameter.isGlobal}
                onCheckedChange={(checked) => updateParameter({ isGlobal: checked })}
              />
              <Label htmlFor="isGlobal">Global</Label>
            </div>
          </div>

          {(parameter.parameterType === "Flag" || parameter.parameterType === "Option") && (
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label>Short Flag (include prefix)</Label>
                <Input
                  value={parameter.shortFlag}
                  onChange={(e) => updateParameter({ shortFlag: e.target.value })}
                  placeholder="-v"
                />
              </div>
              <div className="flex flex-col gap-2">
                <Label>
                  Long Flag (include prefix) <span className="ml-1 text-destructive">*</span>
                </Label>
                <Input
                  value={parameter.longFlag}
                  onChange={(e) => updateParameter({ longFlag: e.target.value })}
                  placeholder="--verbose"
                />
              </div>
            </div>
          )}

          {parameter.parameterType === "Option" && (
            <div className="flex flex-col gap-2">
              <Label>
                Key-Value Separator
                <span className="muted">(default is single space)</span>
              </Label>
              <Input
                value={parameter.keyValueSeparator ?? " "}
                onChange={(e) => updateParameter({ keyValueSeparator: e.target.value })}
                placeholder="Default is single space"
              />
            </div>
          )}

          {parameter.parameterType === "Argument" && (
            <div className="flex flex-col gap-2">
              <Label htmlFor="position">Position</Label>
              <Input
                id="position"
                type="number"
                value={parameter.position || 0}
                onChange={(e) =>
                  updateParameter({
                    position: Number.parseInt(e.target.value) || 0,
                  })
                }
                placeholder="0"
              />
            </div>
          )}

          <div className="flex flex-col gap-2">
            <Label>Description</Label>
            <Textarea
              value={parameter.description}
              onChange={(e) => updateParameter({ description: e.target.value })}
              rows={2}
            />
          </div>

          <div className="grid grid-cols-2 items-center gap-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="defaultValue">Default Value</Label>
              <Input
                id="defaultValue"
                value={parameter.defaultValue}
                onChange={(e) => updateParameter({ defaultValue: e.target.value })}
                className={!validation.isValid ? "border-destructive" : ""}
              />
              {!validation.isValid && (
                <p className="mt-1 text-xs text-destructive">{validation.error}</p>
              )}
            </div>
            <div className="flex items-center space-x-4 pt-6">
              <div className="flex items-center space-x-2">
                <Switch
                  id="isRequired"
                  checked={parameter.isRequired}
                  onCheckedChange={(checked) => updateParameter({ isRequired: checked })}
                />
                <Label htmlFor="isRequired">Required</Label>
              </div>
              <div className="flex items-center space-x-2">
                <Switch
                  id="isRepeatable"
                  checked={parameter.isRepeatable}
                  onCheckedChange={(checked) => updateParameter({ isRepeatable: checked })}
                />
                <Label htmlFor="isRepeatable">Repeatable</Label>
              </div>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <Label>Tags</Label>
            <TagsInput
              value={parameter.metadata?.tags || []}
              onValueChange={(tags) => {
                updateParameter({ metadata: { tags } });
              }}
              placeholder="Add tags"
            />
          </div>

          <Separator />

          {/* Dependencies Section */}
          <div>
            <div className="mb-3 flex items-center justify-between">
              <Label
                htmlFor="dependencies"
                className="flex items-center gap-2 text-base font-medium"
              >
                <LinkIcon className="h-4 w-4" />
                Dependencies
              </Label>
              <Button
                size="sm"
                variant="outline"
                onClick={addDependency}
                disabled={availableParameters.length === 0}
              >
                <PlusIcon className="mr-1 h-3 w-3" />
                Add
              </Button>
            </div>
            <div
              className="space-y-2"
              id="dependencies"
            >
              {parameter.dependencies &&
                parameter.dependencies.map((dependency) => (
                  <div
                    key={dependency.key}
                    className="flex items-center gap-2 rounded border p-2"
                  >
                    <Select
                      value={dependency.dependencyType}
                      onValueChange={(value: ParameterDependencyType) =>
                        updateDependency(dependency.key, {
                          dependencyType: value,
                        })
                      }
                    >
                      <SelectTrigger className="w-32">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="requires">Requires</SelectItem>
                        <SelectItem value="conflicts_with">Conflicts</SelectItem>
                      </SelectContent>
                    </Select>
                    <Select
                      value={dependency.dependsOnParameterKey}
                      onValueChange={(value) =>
                        updateDependency(dependency.key, {
                          dependsOnParameterKey: value,
                        })
                      }
                    >
                      <SelectTrigger className="flex-1">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {availableParameters.map((param) => (
                          <SelectItem
                            key={param.key}
                            value={param.key}
                          >
                            {param.name}
                            {param.isGlobal && " (global)"}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => removeDependency(dependency.key)}
                    >
                      <Trash2Icon className="h-3 w-3" />
                    </Button>
                  </div>
                ))}
            </div>
          </div>

          <Separator />

          {/* Validations Section */}
          <div>
            <div className="mb-3 flex items-center justify-between">
              <Label className="flex items-center gap-2 text-base font-medium">
                <ShieldIcon className="h-4 w-4" />
                Validations
              </Label>
              <Button
                size="sm"
                variant="outline"
                onClick={addValidation}
              >
                <PlusIcon className="mr-1 h-3 w-3" />
                Add
              </Button>
            </div>
            <div className="space-y-2">
              {parameter.validations &&
                parameter.validations.map((validation) => (
                  <div
                    key={validation.key}
                    className="flex items-center gap-2 rounded border p-2"
                  >
                    <Select
                      value={validation.validationType}
                      onValueChange={(value: ParameterValidationType) => {
                        const updatedValidations = parameter.validations?.map((v) =>
                          v.key === validation.key ? { ...v, validationType: value } : v,
                        );
                        updateParameter({
                          validations: updatedValidations,
                        });
                      }}
                    >
                      <SelectTrigger className="w-32">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="min_length">Min Length</SelectItem>
                        <SelectItem value="max_length">Max Length</SelectItem>
                        <SelectItem value="min_value">Min Value</SelectItem>
                        <SelectItem value="max_value">Max Value</SelectItem>
                        <SelectItem value="regex">Regex</SelectItem>
                      </SelectContent>
                    </Select>
                    <Input
                      value={validation.validationValue}
                      onChange={(e) => {
                        const updatedValidations = parameter.validations?.map((v) =>
                          v.key === validation.key ? { ...v, validationValue: e.target.value } : v,
                        );
                        updateParameter({
                          validations: updatedValidations,
                        });
                      }}
                      placeholder="Value"
                      className="flex-1"
                    />
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => {
                        const updatedValidations = parameter.validations?.filter(
                          (v) => v.key !== validation.key,
                        );
                        updateParameter({
                          validations: updatedValidations,
                        });
                      }}
                    >
                      <Trash2Icon className="h-3 w-3" />
                    </Button>
                  </div>
                ))}
            </div>
          </div>

          {/* Enum Values Section */}
          {parameter.dataType === "Enum" && (
            <>
              <Separator />
              <div>
                <div className="mb-3 flex items-center justify-between">
                  <Label
                    htmlFor="enum-values"
                    className="text-base font-medium"
                  >
                    Enum Values
                  </Label>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={addEnumValue}
                  >
                    <PlusIcon className="mr-1 h-3 w-3" />
                    Add
                  </Button>
                </div>
                <div
                  className="space-y-2"
                  id="enum-values"
                >
                  {parameter.enumValues?.map((enumValue) => (
                    <div
                      key={enumValue.value}
                      className="flex items-center gap-2 rounded border p-2"
                    >
                      <Input
                        value={enumValue.value}
                        onChange={(e) => {
                          const updatedEnumValues = parameter.enumValues?.map((ev) =>
                            ev.value === enumValue.value ? { ...ev, value: e.target.value } : ev,
                          );
                          updateParameter({
                            enumValues: updatedEnumValues,
                          });
                        }}
                        placeholder="value"
                        className="flex-1"
                      />
                      <Input
                        value={enumValue.displayName}
                        onChange={(e) => {
                          const updatedEnumValues = parameter.enumValues?.map((ev) =>
                            ev.value === enumValue.value ? { ...ev, displayName: e.target.value } : ev,
                          );
                          updateParameter({
                            enumValues: updatedEnumValues,
                          });
                        }}
                        placeholder="Display Name"
                        className="flex-1"
                      />
                      <Switch
                        checked={enumValue.isDefault}
                        onCheckedChange={(checked) => {
                          const updatedEnumValues = parameter.enumValues?.map((ev) =>
                            ev.value === enumValue.value ? { ...ev, isDefault: checked } : ev,
                          );
                          updateParameter({
                            enumValues: updatedEnumValues,
                          });
                        }}
                      />
                      <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => {
                          const updatedEnumValues = parameter.enumValues?.filter(
                            (ev) => ev.value !== enumValue.value,
                          );
                          updateParameter({
                            enumValues: updatedEnumValues,
                          });
                        }}
                      >
                        <Trash2Icon className="h-3 w-3" />
                      </Button>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={handleClose}
          >
            Cancel
          </Button>
          <Button
            onClick={handleSave}
            disabled={!canSaveChanges()}
          >
            Save Changes
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useToolBuilder } from "../tool-editor.context";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { ExclusionGroup } from "@/registry/commandly/lib/types/commandly";
import { PlusIcon, TrashIcon } from "lucide-react";
import { useState } from "react";

export function ExclusionGroupsDialog() {
  const {
    selectedCommand,
    dialogs,
    getExclusionGroupsForCommand,
    getParametersForCommand,
    setDialogOpen,
    addExclusionGroup,
    updateExclusionGroup,
    removeExclusionGroup,
  } = useToolBuilder();

  const open = dialogs.exclusionGroups;
  const commandKey = selectedCommand?.key;
  const exclusionGroups = commandKey ? getExclusionGroupsForCommand(commandKey) : [];
  const parameters = commandKey ? getParametersForCommand(commandKey) : [];

  const [editingGroup, setEditingGroup] = useState<Partial<ExclusionGroup> | undefined>();

  const handleAddGroup = () => {
    setEditingGroup({
      name: "",
      exclusionType: "mutual_exclusive",
      parameterKeys: [],
      commandKey: selectedCommand?.key,
    });
  };

  const handleSaveGroup = () => {
    if (!editingGroup?.name || !editingGroup.exclusionType) return;

    if (editingGroup.key) {
      updateExclusionGroup(editingGroup as ExclusionGroup);
    } else {
      addExclusionGroup(editingGroup as Omit<ExclusionGroup, "key">);
    }
    setEditingGroup(undefined);
  };

  return (
    <Dialog
      open={open}
      onOpenChange={(open) => setDialogOpen("exclusionGroups", open)}
    >
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Exclusion Groups</DialogTitle>
        </DialogHeader>

        <div className="mt-4 space-y-4">
          {exclusionGroups.map((group) => (
            <div
              key={group.key}
              className="flex items-center justify-between rounded border p-3"
            >
              <div>
                <h4 className="font-medium">{group.name}</h4>
                <div className="mt-1 flex gap-1">
                  {group.parameterKeys.map((key) => {
                    const param = parameters.find((p) => p.key === key);
                    return (
                      param && (
                        <span
                          key={key}
                          className="rounded bg-muted px-1.5 py-0.5 text-xs"
                        >
                          {param.name}
                        </span>
                      )
                    );
                  })}
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setEditingGroup(group)}
                >
                  Edit
                </Button>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => removeExclusionGroup(group.key!)}
                >
                  <TrashIcon className="h-4 w-4" />
                </Button>
              </div>
            </div>
          ))}

          {!editingGroup && (
            <Button
              onClick={handleAddGroup}
              className="w-full"
            >
              <PlusIcon className="mr-2 h-4 w-4" />
              Add Group
            </Button>
          )}

          {editingGroup && (
            <div className="space-y-4 rounded border p-4">
              <div className="space-y-2">
                <Label>Name</Label>
                <Input
                  value={editingGroup.name}
                  onChange={(e) => setEditingGroup({ ...editingGroup, name: e.target.value })}
                  placeholder="Group name"
                />
              </div>

              <div className="space-y-2">
                <Label>Type</Label>
                <Select
                  value={editingGroup.exclusionType}
                  onValueChange={(value) =>
                    setEditingGroup({
                      ...editingGroup,
                      exclusionType: value as ExclusionGroup["exclusionType"],
                    })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="mutual_exclusive">Mutually Exclusive</SelectItem>
                    <SelectItem value="required_one_of">Required One Of</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Parameters</Label>
                <Select
                  value=""
                  onValueChange={(value) =>
                    setEditingGroup({
                      ...editingGroup,
                      parameterKeys: [...(editingGroup.parameterKeys || []), value],
                    })
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Add parameter" />
                  </SelectTrigger>
                  <SelectContent>
                    {parameters
                      .filter((p) => !editingGroup.parameterKeys?.includes(p.key))
                      .map((param) => (
                        <SelectItem
                          key={param.key}
                          value={param.key}
                        >
                          {param.name}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>

                <div className="mt-2 flex flex-wrap gap-1">
                  {editingGroup.parameterKeys?.map((key) => {
                    const param = parameters.find((p) => p.key === key);
                    return (
                      param && (
                        <span
                          key={key}
                          className="flex items-center gap-1 rounded bg-muted px-2 py-1 text-sm"
                        >
                          {param.name}
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-4 w-4 p-0"
                            onClick={() =>
                              setEditingGroup({
                                ...editingGroup,
                                parameterKeys: editingGroup.parameterKeys?.filter(
                                  (pk) => pk !== key,
                                ),
                              })
                            }
                          >
                            <TrashIcon className="h-3 w-3" />
                          </Button>
                        </span>
                      )
                    );
                  })}
                </div>
              </div>

              <div className="mt-4 flex justify-end gap-2">
                <Button
                  variant="outline"
                  onClick={() => setEditingGroup(undefined)}
                >
                  Cancel
                </Button>
                <Button onClick={handleSaveGroup}>Save</Button>
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useToolBuilder } from "../tool-editor.context";
