            <div className="flex flex-col gap-3">
              <Label htmlFor="tool-display-name">Supported Output</Label>
              <MultiSelect
                options={supportedOutputOptions}
                onValueChange={(value) =>
                  updateTool({
                    metadata: {
                      ...tool.metadata,
                      supportedOutput: value.map((v) => v as SupportedToolOutputType),
                    } as ToolMetadata,
                  })
                }
                defaultValue={tool.metadata?.supportedOutput}
                placeholder="Select output types"
                variant="default"
                maxCount={0}
              />
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <Label htmlFor="tool-url">URL</Label>
            <Input
              id="tool-url"
              value={tool.url ?? ""}
              onChange={(e) => updateTool({ url: e.target.value || undefined })}
              placeholder="https://example.com"
            />
          </div>

          <div className="flex flex-col gap-2">
            <Label>Tags</Label>
            <TagsInput
              value={tool.tags || []}
              onValueChange={(tags) => {
