              id="tool-description"
              value={tool.description}
              onChange={(e) => updateTool({ description: e.target.value })}
              rows={3}
            />
          </div>
        </div>
        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => setDialogOpen("editTool", false)}
          >
            Close
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useToolBuilder } from "../tool-editor.context";
import { Button } from "@/components/ui/button";
import {
