                id="sort-order"
                type="number"
                value={editCommand.sortOrder}
                onChange={(e) =>
                  setCommand((prev) => ({
                    ...prev,
                    sortOrder: Number.parseInt(e.target.value) || 0,
                  }))
                }
              />
            </div>
            <div className="flex items-center space-x-2 pt-6">
              <Switch
                id="default-cmd"
                defaultChecked={editCommand.isDefault}
                disabled={command?.isDefault}
                onCheckedChange={(checked) => {
                  setCommand((prev) => ({
                    ...prev,
                    isDefault: checked,
                  }));
                }}
              />
              <Label htmlFor="default-cmd">Default Command</Label>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <Label htmlFor="cmd-desc">Description</Label>
            <Textarea
              id="cmd-desc"
              value={editCommand.description}
              onChange={(e) => setCommand((prev) => ({ ...prev, description: e.target.value }))}
              rows={3}
            />
          </div>
        </div>
        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => {
              updateCommand(editCommand.key, editCommand);
              onOpenChange(false);
            }}
          >
            Save & Close
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useToolBuilder } from "../tool-editor.context";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { SavedCommand } from "@/registry/commandly/lib/types/commandly";
import { SaveIcon, CopyIcon, Trash2Icon } from "lucide-react";
import { toast } from "sonner";

interface SavedCommandsDialogProps {
  savedCommands: SavedCommand[];
  onDeleteCommand: (commandKey: string) => void;
}

export function SavedCommandsDialog({ savedCommands, onDeleteCommand }: SavedCommandsDialogProps) {
  const { dialogs, setDialogOpen } = useToolBuilder();
  const copyCommand = (command: string) => {
    navigator.clipboard.writeText(command);
    toast("Command copied!");
  };

  const deleteCommand = (commandKey: string) => {
    onDeleteCommand(commandKey);
    toast("Command Removed", {
      description: "Saved command has been removed successfully.",
    });
  };

  const open = dialogs.savedCommands;

  return (
    <Dialog
      open={open}
      onOpenChange={() => setDialogOpen("savedCommands", false)}
    >
      <DialogContent className="max-h-[80vh] max-w-4xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <SaveIcon className="h-5 w-5" />
            Saved Commands
          </DialogTitle>
        </DialogHeader>

        {savedCommands.length === 0 ? (
          <div className="py-8 text-center">
            <SaveIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
            <p className="text-muted-foreground">
              No saved commands yet. Generate and save commands to see them here.
            </p>
          </div>
        ) : (
          <div className="max-h-[calc(80vh-8rem)] space-y-4 overflow-y-auto pr-4">
            {savedCommands &&
              savedCommands.length > 0 &&
              savedCommands.map((savedCommand) => (
                <div
                  key={savedCommand.key}
                  className="space-y-3 rounded-lg border p-3"
                >
                  <div className="flex items-center justify-end gap-2">
                    <Button
                      variant="ghost"
                      size="icon"
